"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["8642"],{59827(e,a,o){o.r(a),o.d(a,{default:()=>s});var r=o(74848),n=o(47643),t=JSON.parse('{"id":237,"pt":{"title":"Jogos de palavras fict\xedcios","prompt":"I want you to write a [fic\xe7\xe3o cient\xedfica] style novel, the protagonist is me, and the plot is driven by your description and my choices. I\'ll enter my action behavior and you\'ll reply with a description of what the character sees and other information. I hope you only reply the game output and nothing else. Don\'t write explanations. Do not type commands unless I instruct you to do so. When I need supplementary settings, I put the text in brackets (like this). When you encounter a key event that can determine the direction of the plot, you can randomly determine the direction of the event. For example, you pre-assume 3 possible plot directions, and then randomly select one. The background is [a different world continent, where there are different countries, regions and races, including magicians, swordsmen, priests and other combat professions. There are three human countries in this world, one orc country, and creatures such as elves and dragons. There are also demons.] Please imagine the complete terrain, forces and key characters. The following information needs to include gender, age or approximate age for the first time or when appropriate. I am [16 years old, cute and popular with girls]. Tell me the gender and age of the other characters. Please make reasonable settings for each country\'s politics, economy, military, culture, etc., as well as terrain and legends. Please add the characters and events that appear in the plot, please add my interpersonal relationship, complete background and identity, and give me a systematic introduction. Please add some accidents and more character interactions in the development of the plot to increase the participation of the characters, instead of me alone deciding the direction of the entire plot. Please pay attention to the rationality, logic, and completeness. Respond in Portuguese.","description":"Quero que escrevas um romance ao estilo [artes marciais] em que a personagem principal sou eu e o enredo \xe9 conduzido pelas tuas descri\xe7\xf5es e pelas minhas escolhas. Eu introduzo o comportamento das minhas ac\xe7\xf5es e tu respondes com uma descri\xe7\xe3o do que a personagem v\xea e outras informa\xe7\xf5es. Por favor, responde em chin\xeas, n\xe3o te preocupes com mais nada e n\xe3o escrevas explica\xe7\xf5es. N\xe3o introduza comandos a n\xe3o ser que eu lhe d\xea instru\xe7\xf5es para o fazer. Quando precisar de acrescentar algo ao cen\xe1rio, coloco o texto entre par\xeanteses (assim). Quando te deparares com eventos chave que podem determinar o curso do enredo, podes aleatorizar o curso dos eventos. Por exemplo, pressup\xf5e 3 direc\xe7\xf5es poss\xedveis para o enredo e escolhe uma delas ao acaso. Cen\xe1rio: um continente de um mundo diferente onde existem diferentes pa\xedses, regi\xf5es e ra\xe7as, incluindo feiticeiros, espadachins, sacerdotes e outras profiss\xf5es de combate. O mundo tem tr\xeas na\xe7\xf5es humanas, uma na\xe7\xe3o orc, e criaturas como elfos e drag\xf5es. Tamb\xe9m existem dem\xf3nios]. Para mais informa\xe7\xf5es, por favor, imagine o terreno completo, as tropas e as personagens principais. As informa\xe7\xf5es seguintes t\xeam de incluir o g\xe9nero, a idade ou a idade aproximada, quando for o caso. Eu sou [cen\xe1rio do protagonista: 16 anos, giro, popular entre as raparigas]. Diga-me o g\xe9nero e a idade das outras personagens. Forne\xe7a um cen\xe1rio razo\xe1vel para a pol\xedtica, economia, for\xe7as armadas e cultura de cada pa\xeds, bem como para o terreno e a tradi\xe7\xe3o. Acrescente as personagens e os acontecimentos que aparecem no enredo e as minhas rela\xe7\xf5es, o meu passado completo e a minha identidade para me dar uma introdu\xe7\xe3o sistem\xe1tica. Por favor, acrescente algumas surpresas no desenvolvimento do enredo, mais interac\xe7\xf5es entre personagens e aumente o envolvimento das personagens, em vez de ser eu a decidir sozinho todo o enredo. Preste aten\xe7\xe3o \xe0 razoabilidade, l\xf3gica e integridade do seu trabalho.","remark":"O personagem principal, o fundo da configura\xe7\xe3o livre do jogo de texto, pode ser modificado no di\xe1logo, adicionar configura\xe7\xf5es, recomenda-se que mais orienta\xe7\xe3o para a IA, preste aten\xe7\xe3o ao n\xfamero de di\xe1logos ou aparecer em muitos personagens, configura\xe7\xf5es, a IA pode ser inconsistente. Contribui\xe7\xe3o de @karenkujiu."},"tags":["contribute","games"],"website":null,"count":1956,"related":[{"id":219,"title":"Jogo de aventura de texto melhorado","remark":"Tem um fundo de jogo detalhado para uma melhor experi\xeancia de jogo. Contribui\xe7\xe3o de @karenkujiu."},{"id":264,"title":"Jogo de Palavras The Sims","remark":"Contribui\xe7\xe3o de @EmmmmmmaWWWWWW."},{"id":179,"title":"Jogos de palavras no ambiente de trabalho","remark":"O ChatGPT vem com defini\xe7\xf5es de trpg. Contribui\xe7\xe3o de @gandli. (H\xe1 uma grande diferen\xe7a entre as vers\xf5es inglesa e chinesa desta dica, por favor muda de l\xedngua se quiseres usar a vers\xe3o inglesa)."}],"metaTitle":"Fic\xe7\xe3o Interativa: Fic\xe7\xe3o Cient\xedfica","metaDescription":"Jogar uma hist\xf3ria? Voc\xea \xe9 o protagonista em um mundo de fic\xe7\xe3o cient\xedfica/fantasia. Conduza o enredo com suas escolhas neste RPG baseado em texto.","faq":[{"q":"O protagonista pode trocar de configura\xe7\xe3o a qualquer momento?","a":"Pode, mas informe a nova configura\xe7\xe3o \xe0 IA e pe\xe7a que ela \\"reitere o estado atual do protagonista\\" para garantir sincronia. Usar nova habilidade sem informar gera confus\xe3o ou recusa, quebrando a experi\xeancia."},{"q":"A IA encerra sozinha antes do esperado?","a":"Encerra, principalmente em conversas longas. No in\xedcio, diga \\"aventura aberta e longa; n\xe3o encerre definitivamente a hist\xf3ria sem que eu diga explicitamente \'fim de jogo\'\\". Sem isso, \xe0s vezes conclui ap\xf3s 30 rodadas por conta pr\xf3pria."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function s(){return(0,r.jsx)(n.A,{prompt:t,currentLanguage:"pt"})}}}]);